actionConfiguration.body:
select *
from public.save_contact_master(
  {{
    appsmith.store.contact_form_mode === "edit"
      ? Number(appsmith.store.current_contact_id)
      : null
  }}::bigint,

  {{ appsmith.store.current_client_id }}::uuid,

  {{ inpContactName.text?.trim() || null }}::text,
  {{ inpContactTitle.text?.trim() || null }}::text,
  {{ inpContactPhone.text?.trim() || null }}::text,
  {{ inpContactMobile.text?.trim() || null }}::text,
  {{ inpContactEmail.text?.trim() || null }}::text,
  {{ inpContactNotes.text?.trim() || null }}::text,
  {{ chkContactActive.isChecked !== false }}::boolean,

  {{
    `{${(mslContactCustomers.selectedOptionValues || [])
      .map(Number)
      .filter(Boolean)
      .join(",")}}`
  }}::bigint[],

  {{
    `{${(mslContactVenues.selectedOptionValues || [])
      .map(Number)
      .filter(Boolean)
      .join(",")}}`
  }}::bigint[]
);
